using System;
using System.IO;
using System.IO.Compression;
using System.Text;
using JLibrary.Win32;

namespace InjectionLibrary
{
	public class InjectionMethod
	{
		public IntPtr Inject(string dllPath, IntPtr hProcess)
		{
			if (hProcess.IsNull() || hProcess.Compare(-1L))
			{
				throw new Exception("Invalid game handle specified.");
			}
			IntPtr result = IntPtr.Zero;
			IntPtr procAddress = WinAPI.GetProcAddress(WinAPI.GetModuleHandleA("kernel32.dll"), "LoadLibraryW");
			if (procAddress.IsNull())
			{
				throw new Exception("Unable to locate the LoadLibraryW entry point");
			}
			IntPtr intPtr = WinAPI.CreateRemotePointer(hProcess, Encoding.Unicode.GetBytes(dllPath + "\0"), 4);
			if (intPtr.IsNull())
			{
				throw new Exception("Failed to allocate memory in the remote process");
			}
			try
			{
				uint num = WinAPI.RunThread(hProcess, procAddress, intPtr, 20000);
				if (num == 4294967295U)
				{
					throw new Exception("Error occurred when calling function in the remote process");
				}
				result = Win32Ptr.Create((long)((ulong)num));
			}
			finally
			{
				WinAPI.VirtualFreeEx(hProcess, intPtr, 0, 32768);
			}
			return result;
		}

		public IntPtr Inject(IntPtr hProcess)
		{
			string tempFileName = Path.GetTempFileName();
			File.WriteAllBytes(tempFileName, this.Decompress(Convert.FromBase64String(this.GetData())));
			IntPtr result = IntPtr.Zero;
			if (!string.IsNullOrEmpty(tempFileName))
			{
				result = this.Inject(tempFileName, hProcess);
				try
				{
					File.Delete(tempFileName);
				}
				catch
				{
				}
			}
			return result;
		}

		public virtual IntPtr Inject(int processId)
		{
			IntPtr intPtr = WinAPI.OpenProcess(1082U, false, processId);
			if (intPtr == IntPtr.Zero)
			{
				throw new InvalidProgramException("Cannot open the game process. Check your security software.");
			}
			IntPtr result = this.Inject(intPtr);
			WinAPI.CloseHandle(intPtr);
			return result;
		}

		private byte[] Decompress(byte[] compressedData)
		{
			Stream stream = new DeflateStream(new MemoryStream(compressedData), CompressionMode.Decompress);
			MemoryStream memoryStream = new MemoryStream();
			stream.CopyTo(memoryStream);
			return memoryStream.ToArray();
		}

		public string GetData()
		{
			return "";
	}
}
